import{_ as e,c as i,S as a,o as s}from"./chunks/framework.CsEN6QFL.js";const k=JSON.parse('{"title":"Container Image","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"internal/container-image.md","filePath":"internal/container-image.md","lastUpdated":1776165494000}'),n={name:"internal/container-image.md"};function l(o,t,d,h,r,p){return s(),i("div",null,t[0]||(t[0]=[a(`<h1 id="container-image" tabindex="-1">Container Image <a class="header-anchor" href="#container-image" aria-label="Permalink to &quot;Container Image&quot;">​</a></h1><p>The simulation pipeline runs inside a Docker/Shifter image built from the <a href="https://github.com/OpenDataDetector/sw" target="_blank" rel="noreferrer">OpenDataDetector/sw</a> repository.</p><p><strong>Current tag:</strong> <code>ghcr.io/opendatadetector/sw:0.2.2_linux-ubuntu24.04_gcc-13.3.0</code></p><h2 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Software</th><th style="text-align:left;">Version</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;">MadGraph</td><td style="text-align:left;">5.3.9</td><td style="text-align:left;">NLO generation</td></tr><tr><td style="text-align:left;">Pythia</td><td style="text-align:left;">8.313</td><td style="text-align:left;">Parton shower + hadronisation</td></tr><tr><td style="text-align:left;">DD4hep (ddsim)</td><td style="text-align:left;">—</td><td style="text-align:left;">Geant4-based detector simulation</td></tr><tr><td style="text-align:left;">Geant4</td><td style="text-align:left;">11.3</td><td style="text-align:left;">Transport engine</td></tr><tr><td style="text-align:left;">ROOT</td><td style="text-align:left;">6.38</td><td style="text-align:left;">I/O and analysis framework</td></tr><tr><td style="text-align:left;">HepMC3</td><td style="text-align:left;">3.3</td><td style="text-align:left;">Event record format</td></tr><tr><td style="text-align:left;">ACTS</td><td style="text-align:left;">main (999.999.999)</td><td style="text-align:left;">Track reconstruction</td></tr><tr><td style="text-align:left;">GCC</td><td style="text-align:left;">13.3.0</td><td style="text-align:left;">Build toolchain</td></tr><tr><td style="text-align:left;">Python</td><td style="text-align:left;">3.12</td><td style="text-align:left;">System Python</td></tr></tbody></table><h2 id="runtime-setup" tabindex="-1">Runtime setup <a class="header-anchor" href="#runtime-setup" aria-label="Permalink to &quot;Runtime setup&quot;">​</a></h2><p><code>scripts/cli/setup_container_env.sh</code> (sourced automatically by the pipeline runner) handles first-run setup inside the container:</p><ol><li><strong>ACTS Python bindings</strong> — symlink <code>&lt;prefix&gt;/python/</code> → <code>/tmp/acts</code> so <code>import acts</code> works (workaround for non-standard install path)</li><li><strong>ODD v4.0.4</strong> — clone from CERN GitLab, build <code>libOpenDataDetector.so</code> via CMake, cache in <code>.cache/odd-v4-install/</code></li><li><strong>Geant4 data</strong> — download ~2 GB of physics datasets into <code>.cache/g4data/</code></li><li><strong>Pip packages</strong> — install <code>pyarrow</code>, <code>uproot</code>, <code>pandas</code>, <code>awkward</code>, <code>h5py</code>, <code>tqdm</code>, <code>pyhepmc</code>, <code>psutil</code>, <code>pyedm4hep</code> into <code>.cache/pip/</code></li><li><strong>MG5aMC_PY8_interface</strong> — compile the MadGraph–Pythia8 interface with explicit HepMC2 flags (see known issues below)</li></ol><h2 id="known-issues-fix-in-next-image-build" tabindex="-1">Known issues (fix in next image build) <a class="header-anchor" href="#known-issues-fix-in-next-image-build" aria-label="Permalink to &quot;Known issues (fix in next image build)&quot;">​</a></h2><h3 id="_1-missing-bc-command" tabindex="-1">1. Missing <code>bc</code> command <a class="header-anchor" href="#_1-missing-bc-command" aria-label="Permalink to &quot;1. Missing \`bc\` command&quot;">​</a></h3><p>MadGraph checks for <code>bc</code> to calculate shower parameters. Without it, MadGraph falls back to <code>noshower</code> mode and only produces LHE files.</p><p><strong>Fix:</strong> <code>apt-get install -y bc</code> in the Dockerfile.</p><h3 id="_2-mg5amc-py8-interface-incompatible-with-pythia-8-3" tabindex="-1">2. mg5amc_py8_interface incompatible with Pythia 8.3+ <a class="header-anchor" href="#_2-mg5amc-py8-interface-incompatible-with-pythia-8-3" aria-label="Permalink to &quot;2. mg5amc_py8_interface incompatible with Pythia 8.3+&quot;">​</a></h3><p>The C++ driver MadGraph uses to steer Pythia showering only works with Pythia 8.2.x. This blocks NLO+PS generation (ttbar, SUSY, etc.).</p><p><strong>Current workaround</strong> (in <code>setup_container_env.sh</code>): compile the interface directly with explicit HepMC2 flags:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">g++</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MG5aMC_PY8_interface.cc -o MG5aMC_PY8_interface </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PY8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/include</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HEPMC2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/include</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ZLIB</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/include</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -O2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -std=c++20</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fPIC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -pthread</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DGZIP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PY8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/lib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Wl,-rpath,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PY8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/lib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lpythia8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HEPMC2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/lib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Wl,-rpath,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HEPMC2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/lib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lHepMC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    -L</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ZLIB</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/lib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Wl,-rpath,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ZLIB</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">/lib</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ldl</span></span></code></pre></div><p><strong>Long-term fix:</strong> pre-install the interface with <code>--pythia8_makefile</code> during image build, or port the interface to the Pythia 8.3 API.</p><h3 id="_3-missing-pyedm4hep" tabindex="-1">3. Missing <code>pyedm4hep</code> <a class="header-anchor" href="#_3-missing-pyedm4hep" aria-label="Permalink to &quot;3. Missing \`pyedm4hep\`&quot;">​</a></h3><p>The <code>convert_all.py</code> postprocessing script needs <code>pyedm4hep</code>. Added to the pip install list in <code>setup_container_env.sh</code> as a workaround.</p><p><strong>Fix:</strong> add <code>pyedm4hep</code> to the image&#39;s pip install layer.</p><h3 id="_4-acts-python-bindings-path" tabindex="-1">4. ACTS Python bindings path <a class="header-anchor" href="#_4-acts-python-bindings-path" aria-label="Permalink to &quot;4. ACTS Python bindings path&quot;">​</a></h3><p>ACTS installs to <code>&lt;prefix&gt;/python/</code> instead of <code>&lt;prefix&gt;/lib/pythonX.Y/site-packages/acts/</code>. The setup script works around this with a symlink.</p><p><strong>Fix:</strong> adjust the ACTS spack recipe to install into <code>site-packages</code>, or ship an <code>acts.pth</code> file.</p><h2 id="build-checklist-for-next-image" tabindex="-1">Build checklist for next image <a class="header-anchor" href="#build-checklist-for-next-image" aria-label="Permalink to &quot;Build checklist for next image&quot;">​</a></h2><ul><li>[ ] Add <code>bc</code> to system packages</li><li>[ ] Pre-compile <code>MG5aMC_PY8_interface</code> with HepMC2 dynamic linking</li><li>[ ] Add <code>pyedm4hep</code> to pip install layer</li><li>[ ] Fix ACTS Python install path (or add <code>.pth</code> file)</li><li>[ ] Verify <code>run_pipeline_docker.sh --channel ttbar</code> completes NLO+PS without the <code>setup_container_env.sh</code> workaround</li><li>[ ] Tag as <code>0.3.0</code> and update <code>CONTAINER_IMAGE</code> defaults in backend <code>.env.example</code> and <code>colliderml/simulate/docker.py</code></li></ul><h2 id="cache-layout" tabindex="-1">Cache layout <a class="header-anchor" href="#cache-layout" aria-label="Permalink to &quot;Cache layout&quot;">​</a></h2><p>All caches are stored under <code>&lt;repo&gt;/.cache/</code> (gitignored) on the host, bind-mounted into the container:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>.cache/</span></span>
<span class="line"><span>├── odd-v4/              # ODD v4.0.4 source (XML geometry)</span></span>
<span class="line"><span>├── odd-v4-install/      # Built libOpenDataDetector.so</span></span>
<span class="line"><span>├── g4data/              # Geant4 physics datasets (~2 GB)</span></span>
<span class="line"><span>├── pip/                 # Python packages for postprocessing</span></span>
<span class="line"><span>└── MG5aMC_PY8_interface/ # Compiled MG5-Pythia8 interface binary</span></span></code></pre></div>`,28)]))}const g=e(n,[["render",l]]);export{k as __pageData,g as default};
